              <div style={{ fontSize:11, color:"#ffd9b8", fontWeight:600, background:"rgba(255,140,66,0.22)", border:"1px solid rgba(255,140,66,0.4)", display:"inline-block", padding:"3px 11px", borderRadius:18, marginTop:3 }}>{t.trendD}</div>
